// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const forecastItems = useMemo(() => {
    const items = Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : [];
    return Array.from({ length: 5 }, (_, index) => items[index] ?? {});
  }, [props.forecast]);
  const conditionText = useMemo(() => props.condition || 'Unknown', [props.condition]);
  const unitLabel = props.unit ? props.unit.toUpperCase() : '°';
  const normalizedCondition = conditionText.toLowerCase();
  const weatherEmoji = useMemo(() => {
    if (normalizedCondition.includes('thunder')) return '⛈️';
    if (normalizedCondition.includes('snow') || normalizedCondition.includes('sleet')) return '🌨️';
    if (normalizedCondition.includes('rain') || normalizedCondition.includes('drizzle')) return '🌧️';
    if (normalizedCondition.includes('fog') || normalizedCondition.includes('mist') || normalizedCondition.includes('haze')) return '🌫️';
    if (normalizedCondition.includes('cloud')) return '☁️';
    if (normalizedCondition.includes('wind')) return '🌬️';
    if (normalizedCondition.includes('clear') || normalizedCondition.includes('sun')) return '☀️';
    return '🌤️';
  }, [normalizedCondition]);
  const weatherLabel = useMemo(() => `${conditionText} in ${props.city}`, [conditionText, props.city]);
  const maxTemp = useMemo(() => {
    if (!forecastItems.length) return props.temperature;
    const values = forecastItems.map((item) => typeof item.high === 'number' ? item.high : props.temperature);
    return values.reduce((highest, value) => Math.max(highest, value), values[0]);
  }, [forecastItems, props.temperature]);
  const minTemp = useMemo(() => {
    if (!forecastItems.length) return props.temperature;
    const values = forecastItems.map((item) => typeof item.low === 'number' ? item.low : props.temperature);
    return values.reduce((lowest, value) => Math.min(lowest, value), values[0]);
  }, [forecastItems, props.temperature]);
  const formatTemp = useCallback((value?: number) => {
    if (typeof value !== 'number' || Number.isNaN(value)) return '—';
    return `${Math.round(value)}°${unitLabel}`;
  }, [unitLabel]);
  const formatDay = useCallback((day?: string, index?: number) => {
    if (day && day.trim()) return day;
    if (typeof index === 'number') return `Day ${index + 1}`;
    return '—';
  }, []);
  const forecastIcon = useCallback((icon?: string, day?: string) => {
    const source = `${icon || ''} ${day || ''} ${normalizedCondition}`.toLowerCase();
    if (source.includes('thunder')) return '⛈️';
    if (source.includes('snow') || source.includes('sleet')) return '🌨️';
    if (source.includes('rain') || source.includes('drizzle')) return '🌧️';
    if (source.includes('fog') || source.includes('mist') || source.includes('haze')) return '🌫️';
    if (source.includes('cloud')) return '☁️';
    if (source.includes('wind')) return '🌬️';
    if (source.includes('sun') || source.includes('clear')) return '☀️';
    return icon && icon.trim() ? icon : '🌤️';
  }, [normalizedCondition]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="lg"
        radius="xl"
        border
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Row gap="var(--ggui-spacing-4)" align="center">
            <Box
              padding="var(--ggui-spacing-4)"
              background="var(--ggui-color-primary-50)"
              borderRadius="var(--ggui-shape-radius-xl)"
            >
              <Text variant="bodyLarge" size="4xl" is="span">{weatherEmoji}</Text>
            </Box>
            <Stack gap="var(--ggui-spacing-1)">
              <Text variant="overline" color="var(--ggui-color-primary-700)">Current Weather</Text>
              <Heading level={2}>{props.city}</Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">{weatherLabel}</Text>
            </Stack>
          </Row>

          <Row gap="var(--ggui-spacing-4)" wrap align="stretch">
            <Card padding="var(--ggui-spacing-4)" shadow="none" radius="lg" border>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Temperature</Text>
                <Heading level={1} color="var(--ggui-color-primary-600)">{formatTemp(props.temperature)}</Heading>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Feels prominent and current</Text>
              </Stack>
            </Card>
            <Card padding="var(--ggui-spacing-4)" shadow="none" radius="lg" border>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Heading level={3}>{`${Math.round(props.humidity)}%`}</Heading>
              </Stack>
            </Card>
            <Card padding="var(--ggui-spacing-4)" shadow="none" radius="lg" border>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                <Heading level={3}>{`${Math.round(props.windSpeed)} ${props.unit}`}</Heading>
              </Stack>
            </Card>
          </Row>

          <Divider margin="var(--ggui-spacing-2)" />

          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={4}>5-Day Forecast</Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">High / Low by day</Text>
            </Row>
            <Row gap="var(--ggui-spacing-3)" wrap>
              {forecastItems.map((item, index) => (
                <Card
                  as={Clickable}
                  key={`${formatDay(item.day, index)}-${index}`}
                  padding="var(--ggui-spacing-4)"
                  shadow="none"
                  radius="lg"
                  border
                  aria-label={`Forecast for ${formatDay(item.day, index)}`}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center">
                    <Text variant="label" align="center">{formatDay(item.day, index)}</Text>
                    <Text variant="bodyLarge" is="span" align="center">{forecastIcon(item.icon, item.day)}</Text>
                    <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant)">
                      {`${formatTemp(item.high)} / ${formatTemp(item.low)}`}
                    </Text>
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>

          <Divider margin="var(--ggui-spacing-2)" />

          <Row gap="var(--ggui-spacing-2)" wrap>
            <Badge variant="primary">{`${Math.round(props.humidity)}% Humidity`}</Badge>
            <Badge variant="secondary">{`Wind ${Math.round(props.windSpeed)} ${props.unit}`}</Badge>
            <Badge variant="info">{`Range ${formatTemp(maxTemp)} / ${formatTemp(minTemp)}`}</Badge>
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}
